<?php
namespace App\Http\Controllers\Api;use App\Http\Controllers\Controller;use App\Http\Resources\ApiResponse;use App\Http\Resources\DeliveryResource;use App\Models\Delivery;use App\Models\Order;use Illuminate\Http\JsonResponse;use Illuminate\Support\Facades\Auth;class DeliveryController extends Controller{public function index(): JsonResponse{$deliveries=Delivery::with(['order','rider'])->where('rider_id',Auth::id())->latest()->paginate(20);return new ApiResponse(DeliveryResource::collection($deliveries));}public function store(\App\Http\Requests\DeliveryStoreRequest $request): JsonResponse{$order=Order::findOrFail($request->order_id);if($order->delivery()->exists()){return new ApiResponse(null,'Delivery already assigned',422);}$delivery=$order->delivery()->create(['rider_id'=>Auth::id(),'status'=>'pending',]);$order->update(['status'=>'processing']);return new ApiResponse(new DeliveryResource($delivery->load('order')),'Delivery assigned',201);}public function show(string $id): JsonResponse{$delivery=Delivery::with(['order.items.product','rider'])->findOrFail($id);if($delivery->rider_id!==Auth::id()&&!Auth::user()->isAdmin()){return new ApiResponse(null,'Forbidden',403);}return new ApiResponse(new DeliveryResource($delivery));}public function updateStatus(\App\Http\Requests\DeliveryStatusRequest $request,string $id): JsonResponse{$delivery=Delivery::findOrFail($id);if($delivery->rider_id!==Auth::id()&&!Auth::user()->isAdmin()){return new ApiResponse(null,'Forbidden',403);}$delivery->update($request->validated());if($request->status==='delivered'){$delivery->order->update(['delivery_status'=>'delivered','status'=>'delivered']);}return new ApiResponse(new DeliveryResource($delivery->fresh()->load('order')),'Delivery status updated');}}